import{_ as a,o as e,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const N=JSON.parse('{"title":"PAX-12 丧尸病毒","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/PAX-12 丧尸病毒.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/PAX-12 丧尸病毒.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/PAX-12 丧尸病毒.md"};function A(d,b,o,D,_,l){return e(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"pax-12-丧尸病毒",tabindex:"-1"},[t("PAX-12 丧尸病毒 "),r("a",{class:"header-anchor",href:"#pax-12-丧尸病毒","aria-label":'Permalink to "PAX-12 丧尸病毒"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="pax-12-丧尸病毒-1" tabindex="-1">PAX-12 丧尸病毒 <a class="header-anchor" href="#pax-12-丧尸病毒-1" aria-label="Permalink to &quot;PAX-12 丧尸病毒&quot;">​</a></h1><p>PAX-12 丧尸病毒</p><p>一次性血统<br> 价格：D+600<br> 不论你是因为吃到了不干净的食物，还是接触了一些可爱的小动物，亦或是亲吻了自己所心爱的女士。总之，你成为了PAX-12病毒的一名感染者。<br> 你开始渐渐的失眠，身体开始分泌出往常的好几倍唾沫，回过神来时，才发现满桌的食物己然被你一扫而空。<br> 你愈发变得狂躁，只有啃食鲜活的肉体才会令你感到愉悦，当你看着满地的残骸才发现自己已经变得愈加陌生。<br> 突然，无边的黑暗将你笼罩，死因是内出血，也或是急性脑炎，或者其他的些什么但这些都已不再重要。<br> 复杂的神经系统开始重构，死去的细胞开始渐渐复活，身体的重要器官恢复了些许低级功能，在此刻，你成为了丧尸的一员，不过值得庆幸的是被主神改造后，你仍然能保留自身的意识。</p><p>【厌氧复生】：受感染的脑细胞开始转变为无氧呼吸模式,因此你不再需要呼吸氧气,也不需要睡眠来进行休息，但因此在脑内大量堆积的乳酸会渐渐的开始摧毁脑部高级进程和人格。<br> 【亡者之躯】:丧尸的躯体是由死者转化而来，因此你不再畏惧伤势带来的死亡，你的生命值转化为你生命值上限1倍的结构值。你死而复生的细胞失去了原本的再生能力，因此你失去了自主恢复生命级的能力并且任何恢复生命值的能力都无法对你起效（但能恢复结构值得能力以及快速医疗依旧能正常的生效。）,同时丧尸将被视为黑暗生物。<br> 【剧毒体液】:丧尸的体液拥有极强的传染性和毒性，被咬的幸存者往往几个小时之内便会彻底被转化，不过主神为了控制对世界的影响，去除了其本身的传染能力，但依旧保持了其原本的毒性。当一个并非丧尸的生物，被你的体液进入了身体之后，其必须进行一个DC为你耐力上附加成功数+1的强韧检定。如果该检定失败，则被咬者立即受到一点严重伤害，并在接下来的一小时之内，每两分钟都需要经过一次该检定，失败则受到一点严重伤害。这个效果不能叠加，且会在一次成功的长线治疗中被移除。丧尸的全身都将视为3L的天生武器,并且只要这些部位成功造成了伤害，都可以为被攻击的目标注入病毒。<br> 【嗜血性饥渴】:病毒对养分的巨大需求驱使着丧尸去摄入更多血肉，一切除丧尸以外拥有肌肉组织以及血液的生命形态，都是他们所捕食的对象，即便是队友也包括在内。在成为丧尸之后，由于体内大量酸性物质的堆积，因此其对于血肉的摄入量，至少是以前的六倍，并且会更加喜好吃鲜活的生命，吸食他们的血液。如若无法补充足够的血肉，在丧尸见到任何可以猎食的对像之后，其必须通过一个DC等同于未摄入血肉的小时长的检定，若未通过，则会强制对其进行袭击，如果该袭击被强行阻止，则丧尸会丢失一点意志力，且在一切行动上受到3dp减值，直到其补充了足够的血肉。值得注意的是，丧尸极其厌恶摄入同类的血肉，其同类之间也不会自主产生敌意，在争夺食物时例外。同时虽然丧尸极为喜爱摄入大量新鲜血肉，但其几乎停转的新陈代谢足以支撑其不吃不喝十余年。<br> 【腐烂死神】：丧尸的细胞再生能力消失，免疫系统几乎停转，这导致其在任何拥有微生物的环境之下，都会不可避免的渐渐腐烂。因此在任何有着微生物的环境下，丧尸每经过三十天，将会受到一点不可吸收，不可治疗的韧性伤害。该伤害只能回到主神处进行修复，但你每因为这个效果承受一点韧性伤害之后，你的毒素豁免DC上升一点,治疗之后重置。<br> 丧尸的免疫系统虽然几乎停转，但他们体内的病毒，却能为其几乎吞并一切外来的凡俗疾病以及毒素，这视为一个D级免疫毒素和疾病能力。<br> 【感官异常】:丧尸对外界的感知能力，因为神经系统的重构而导致了异化，其对于光线的感知变得异常敏感，因此它可以在漆黑的环境中看清周围的事物，但在日光之下其侦查检定会不可避免地受到3dp减值。<br> 同时，为了增强对新鲜血肉的感知能力，丧尸的嗅觉得到了大幅度的增强，其可以通过嗅觉精准定位敏感范围内捕食对象的位置，这是一种强感知方式。<br> 由于平衡系统的精密性受到了影响，所以导致了丧尸的行动能力比正常人类低其在进行与敏捷相关判定时视为敏捷-2（最低为0）。不过，因为丧尸对于自身限制的神经失去了原有的作用，所以他们往往能发挥出远超常人的力量，在力量相关判定时获得3点增强加值。<br> ——<br> PAX-12 丧尸病毒进化方向<br> DNA点：病毒变异的进化点数，每D+500可购买3点（这视为强化了一个D级技艺），PAX-12病毒后续强化仅可使用DNA点进行购买。</p><p>分段式基因组<br> DNA点数：3<br> 你体内的病毒基因组将会分裂成较小的分子,这将大幅度加快其变异的过程,尤其是在你进入每一个影片看似相同却又完全不同的生态环境中时，陌生微观环境的变化会令其不断地进行适应变化,你每经过一场影片都将获得1点 Dna点数。</p><p>运动神经控制强化<br> DNA点数：2<br> 你的身体会首先将体内的营养物质运输到脑叶，这将极大的改善神经异化对你协调性带来的影响，因此你在进行敏捷相关判定时不再视为敏捷-2，你的运动相关判定额外获得1附加成功.</p><p>肽合成激增<br> DNA点数：2<br> 丧尸体内激素合成量显著增加，将体内脂肪代谢转化为肌肉，大量增殖的肌肉赐予了丧尸远超常人的力量。你的力量增加两点，如果达到属性上限，则改为获得2dp力量相关判定上的增强加值，并使你的天生武器伤害增加1L。<br> 运动系统综合提升:当你强化了运动神经控制强化和肽合成激增后，强大的肌肉和神经反应系统，令你可以轻松的攀行在任何墙体之上，即便其是属于难以攀爬的光滑表面,你获得等同于基础移动速度的攀爬速度。</p><p>肌肉群系综合强化<br> DNA点数：12<br> 前置:肽合成激增，运动神经控制强化。<br> 体内睾酮的分泌量激增，这将显著增加丧尸体内的肌肉密度,令其力量开始超出常人的范畴，因此你的力量相关判定获得【8加骰】，同时神经控制能力的增强，令你可以单独的控制体内任意的一块肌肉，也无需担心会因此伤及自身,此时你的全身都将被视为适用于擒抱的天生武器。<br> 咬合肌强化：你的咬合肌愈发丰满，这令你可以轻易的用牙齿撕开厚重的防御，你的牙齿武器伤害增加2L，并获得等同于你力量上附加成功数的破甲，当你力量上附加成功数达到4时，将额外获得2点破甲。<br> 蚓状肌肥大:你手掌的肌肉量和密度显著增加，尤其是蚓状肌在肥大的同时变为了青黑色，这将显著增加你手掌的握力，使得猎物在被你抓住时更加难以逃脱，当你在进行擒抱检定时，可以将最多等同于你力量上附加成功数的dp转化为附加成功。</p><p>木乃伊化<br> DNA点数：3<br> 你的外壳在病毒的控制下干枯坏死体内水分减少，形成了一屁特殊的保护外壳，这有效的减少了微生物对躯体内部的破坏,你因为微生物腐蚀而承受的伤害改为严重。<br> 硬化的干枯外壳为你提供了极强的适应能力，你因此免受C级环境对你带来的负面影响,你的外壳被视为1活体护甲，且该活体护甲基于天生防御。</p><p>肌肉群系转移式修复<br> DNA点数：3<br> 为了在战斗受创之后迅速恢复，丧尸可以控制自己身上的肌肉群系在自身进行移动,迅速修补自身创伤。当你身上拥有肢体妨碍点数时，你可以以自由动作对自己另外的肢体造成一点不可豁免的肢体妨碍异常点数或对自己造成一点不可豁免的严重伤害修复一点肢体妨碍点数，一回合仅限两次，一天之内你最多通过该方法恢复48点肢体妨碍异常点数。<br> 同时你也可以通过对自己一条肢体造成一点不可豁免的肢体妨碍点数以修复自身一点结构值，一回合仅限一次，一天之内你最多通过该方法恢复12点结构值。</p><p>组织蛋白转移<br> DNA点数：3<br> 大量营养物质流入脑内，令视觉听觉皮层受到刺激，这极大的改善了丧尸的视觉能力，其在阳光之下侦查检定不再受到减值，同时你的视觉拥有了如同蛇类一般的热感知，甚至可以穿越墙体，这令你的视觉升级为一种强感知方式。脑内充斥着的病毒液体，也同时增强了耳蜗的传导功能，令丧尸可以通过听觉，清晰的感觉到周围的所有事物，此时你的听觉也被视为一种强感知方式。</p><p>感知系统综合强化<br> DNA点数：6<br> 前置：组织蛋白转移<br> 大幅度提高流入枕骨和额叶的营养物质，这令丧尸拥有了非人一般的感知能力，任何风吹草动都能成为他们搜索猎物的媒介。此时，你的听觉和视觉感知范围提升一倍。</p><p>皮肤钙化<br> DNA点数：4<br> 内分泌系统的基因突变，导致部分皮肤产生硬化和钙化，令普通的刀具难以破开丧尸的防御，这将显著增加丧尸的战斗能力。<br> 你的身体获得4点天生防御，并获得基于该天生防御的【防弹】特性。</p><p>颇骨像皮症<br> 前置：皮肤钙化<br> DNA点数：8<br> 腺瘤导致生长激素突变，令骨头开始生长在骨头中空的内部，在增加体重的同时，极大的提升了丧尸的生存能力。<br> 你的身体额外获得【防能量武器】特性，紧密的骨骼令你的身体额外获得了【封闭1】特性,你因为皮肤钙化所提供的防御提升2+2×耐力上附加成功数点天生防御。</p><p>骨骼结构异常<br> DNA点数：14<br> 你的骨骼之中不再会充斥细小的空洞，令你的骨密度提升到匪夷所思的地步，同时这也会带来你的体重飙升，因此你的敏捷判定要承受等同于你耐力上附加成功的减值。但相对应的这也为你带来了极为强悍的适应能力,你的天生防御额外获得等同于你耐力上附加成功的附加成功。同时,扎根于全身的骨骼,将彻底改造身体的承受强度,因此你的结构值上限提升为生命值上限的1.5倍。</p><p>再生活化<br> 需求：至少使用了12点DNA点数<br> DNA点数：8<br> 再生生物合成:病毒可以产生修复神经的蛋白质，并会刺激受感染的脑部神经,令其产生可以修复身体的特殊蛋白,因此你获得快速医疗1（医疗点12）。同时在你死亡之后，病毒会优先修复你的身躯，再逐渐的修复你的神经细胞，通常而言，这需要长达一个月的时间，在修复完成之后，你的躯体将会重新复活。在此期间，你的感知功能依旧能正常运行，但你无法做到除了感知外界以外的任何事情。同时在复活期间内，如果你的尸体被摧毁，那么你将彻底死去，这视为一个b级疾病来源的复活效果。</p><p>表皮细胞消化<br> 前置：再生活化<br> DNA点数：12<br> 细胞全能性:你的细胞拥有了如同植物细胞一般的全能性。即使你的遗体受到了损坏，但只要还留有完好的肢体，你就可以借此再生复活。同时对环境的强大适应力令你的遗体【不会损坏】。在你死亡之后,你的身体会分解你的身体表皮,来提供营养,这将极大幅度提升你身体神经的修复时间。因此你通过再生活化复活的时间将被缩短为一周，复活的来源等级提升至A级。</p><p>全身性中枢神经扩展<br> 前置：表皮细胞消化<br> DNA点数：12<br> 冗余无用的肺部被大量新生神经占据，借此令全新的中枢神经系统扩展到了全身。此时，你身体你每一个部位都可以如同你的大脑一样处理信息。同时细胞的全能性也得到极大程度的强化。只要你的结构值没有归零，你无论受到怎样的创伤，就算是大脑被粉碎，内脏被掏空你也依旧不会受到影响，这视为一个s级的免疫创伤效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const c=a(s,[["render",A]]);export{N as __pageData,c as default};
